// // This LFSR uses taps at positions 1, 3, 4, and 6 for feedback.
module lfsr_16bit (  
    input clk,  
    input reset,  
    input [15:0] seed,  
    output reg [15:0] lfsr_out  
);  

    wire feedback;  
    assign feedback = lfsr_out[15] ^ lfsr_out[13] ^ lfsr_out[12] ^ lfsr_out[10];  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            lfsr_out <= seed;  
        end else begin  
            lfsr_out <= {lfsr_out[14:0], feedback};  
        end  
    end  
endmodule
